// Input: Full manuscript text from manuscript document
const manuscriptText = $input.item.json.content || "";

// For debugging
console.log("Manuscript length: ", manuscriptText.length);

// First, try to find full chapter markers using the BEGIN/END pattern
const chapterPattern = /\[BEGIN CHAPTER (\d+)\]([\s\S]*?)\[END CHAPTER \1\]/gi;
const chapters = [];
let match;

while ((match = chapterPattern.exec(manuscriptText)) !== null) {
  const chapterNum = parseInt(match[1]);
  const chapterContent = match[0]; // Full content including markers

  chapters.push({
    number: chapterNum,
    content: chapterContent
  });

  console.log(`Found complete chapter ${chapterNum}`);
}

// If no chapters found with the standard approach, try to handle the specific format in your paste.txt
if (chapters.length === 0) {
  console.log("No standard chapters found, trying alternative format");

  // Split the content by line to process the numbered entries
  const lines = manuscriptText.split('\n');
  let currentChapter = null;
  let collectingChapter = false;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i].trim();

    // Check if this is a chapter number line (starts with "number:")
    if (line.startsWith('number:')) {
      const chapterNum = parseInt(line.substring(7));

      // Start of a new chapter entry
      if (!currentChapter || currentChapter.number !== chapterNum) {
        if (currentChapter && currentChapter.content) {
          chapters.push(currentChapter);
          console.log(`Added chapter ${currentChapter.number} from alternative format`);
        }

        currentChapter = {
          number: chapterNum,
          content: ''
        };
      }
    }
    // Check if this is a content line
    else if (line.startsWith('content:') && currentChapter) {
      // Extract content without the prefix
      let content = line.substring(8);

      // If the next line isn't a new entry marker, it's continuation of content
      let j = i + 1;
      while (j < lines.length && !lines[j].trim().match(/^\d+$/) && !lines[j].trim().startsWith('number:') && !lines[j].trim().startsWith('content:')) {
        content += '\n' + lines[j];
        j++;
      }

      // Append to existing content
      currentChapter.content += content;

      i = j - 1; // Skip the lines we've already processed
    }
  }

  // Add the last chapter if it exists
  if (currentChapter && currentChapter.content) {
    chapters.push(currentChapter);
    console.log(`Added final chapter ${currentChapter.number} from alternative format`);
  }
}

// Sort chapters by number
chapters.sort((a, b) => a.number - b.number);

console.log(`Total chapters found: ${chapters.length}`);
chapters.forEach(ch => console.log(`Chapter ${ch.number}: ${ch.content.substring(0, 50)}...`));

// Determine next chapter to write
const nextChapterNumber = chapters.length > 0 ? chapters[chapters.length - 1].number + 1 : 1;
const isFirstChapter = chapters.length === 0;

// Extract the last 4 chapters for context
const recentChapters = chapters.slice(Math.max(0, chapters.length - 4));

console.log(`Recent chapters (last 4): ${recentChapters.map(ch => ch.number).join(', ')}`);

// Format recent chapters as context string
let recentChaptersText = "";
if (recentChapters.length > 0) {
  recentChaptersText = "### Recent Chapters for Context:\n\n";
  recentChapters.forEach(chapter => {
    // Use the full chapter content without truncation
    recentChaptersText += `Chapter ${chapter.number}:\n${chapter.content}\n\n`;
  });
}

// Get the content of the last chapter for transition analysis
const lastChapterContent = recentChapters.length > 0 ? recentChapters[recentChapters.length - 1].content : "";

return {
  json: {
    nextChapterNumber,
    recentChapters,
    recentChaptersText,
    lastChapterContent,
    isFirstChapter,
    totalChaptersFound: chapters.length
  }
};

// Get the total chapters target from the form submission
let totalChaptersTarget;
try {
  // Changed this line to use your actual form node name
  totalChaptersTarget = parseInt($('On form submission1').item.json['Total Chapters']) || 0;
} catch (error) {
  // Handle case where form data isn't accessible
  totalChaptersTarget = 0;
  console.log('Error accessing Total Chapters:', error.message);
}

// Get the current chapter number - try multiple possible sources
let currentChapterNumber;
try {
  // First try to get from Determine Next Chapter node
  if ($('Determine Next Chapter') && $('Determine Next Chapter').item && $('Determine Next Chapter').item.json) {
    currentChapterNumber = parseInt($('Determine Next Chapter').item.json.nextChapterNumber) || 0;
  } 
  // If that fails, try to parse it from the chapter name or other sources
  else if ($json && $json.nextChapterNumber) {
    currentChapterNumber = parseInt($json.nextChapterNumber) || 0;
  }
  // Default to 1 if all else fails
  else {
    currentChapterNumber = 1;
  }
} catch (error) {
  // Default value if we can't determine chapter number
  currentChapterNumber = 1;
  console.log('Error determining current chapter number:', error.message);
}

// Ensure we have valid numbers for calculations
totalChaptersTarget = Math.max(1, totalChaptersTarget);
currentChapterNumber = Math.max(1, currentChapterNumber);

// Determine if we're done
const isComplete = currentChapterNumber >= totalChaptersTarget;
const percentComplete = Math.round((currentChapterNumber / totalChaptersTarget) * 100);

// Add additional logging to help troubleshoot
console.log('Chapter count data:', {
  currentChapterNumber,
  totalChaptersTarget,
  isComplete,
  percentComplete,
  formNodeExists: !!$('On form submission1')
});

return {
  json: {
    currentChapterNumber,
    totalChaptersTarget,
    isComplete,
    percentComplete
  }
};

// Get the manuscript directly
let manuscriptText = "";
try {
  if ($('Get Manuscript') && $('Get Manuscript').item && $('Get Manuscript').item.json) {
    manuscriptText = $('Get Manuscript').item.json.content || "";
    console.log(`Successfully accessed manuscript, length: ${manuscriptText.length}`);
  } else {
    console.log("Could not access manuscript");
  }
} catch (error) {
  console.log("Error accessing manuscript:", error.message);
}

// Extract chapters directly from the manuscript
const chapters = [];
if (manuscriptText) {
  // Try BEGIN/END pattern first
  const chapterPattern = /\[BEGIN CHAPTER (\d+)\]([\s\S]*?)\[END CHAPTER \1\]/gi;
  let match;

  while ((match = chapterPattern.exec(manuscriptText)) !== null) {
    const chapterNum = parseInt(match[1]);
    const chapterContent = match[0];
    chapters.push({ number: chapterNum, content: chapterContent });
    console.log(`Directly extracted chapter ${chapterNum}`);
  }

  // If no chapters found, try alternative format
  if (chapters.length === 0) {
    console.log("Format Context: No standard chapters found, trying alternative format");
    const lines = manuscriptText.split('\n');
    let currentChapter = null;

    for (let i = 0; i < lines.length; i++) {
      const line = lines[i].trim();

      if (line.startsWith('number:')) {
        const chapterNum = parseInt(line.substring(7));

        if (!currentChapter || currentChapter.number !== chapterNum) {
          if (currentChapter && currentChapter.content) {
            chapters.push(currentChapter);
          }

          currentChapter = { number: chapterNum, content: '' };
        }
      }
      else if (line.startsWith('content:') && currentChapter) {
        let content = line.substring(8);

        let j = i + 1;
        while (j < lines.length && !lines[j].trim().match(/^\d+$/) && 
               !lines[j].trim().startsWith('number:') && 
               !lines[j].trim().startsWith('content:')) {
          content += '\n' + lines[j];
          j++;
        }

        currentChapter.content += content;
        i = j - 1;
      }
    }

    if (currentChapter && currentChapter.content) {
      chapters.push(currentChapter);
    }
  }

  // Sort chapters by number
  chapters.sort((a, b) => a.number - b.number);
  console.log(`Format Context: Total chapters found directly: ${chapters.length}`);
}

// Get the next chapter number from Determine Next Chapter node
let nextChapterNumber = 1;
try {
  if ($('Determine Next Chapter') && 
      $('Determine Next Chapter').item && 
      $('Determine Next Chapter').item.json) {
    nextChapterNumber = $('Determine Next Chapter').item.json.nextChapterNumber || 1;
    console.log(`Next chapter number: ${nextChapterNumber}`);
  }
} catch (error) {
  console.log("Error getting next chapter number:", error.message);
}

// Extract recent chapters (last 4)
const recentChapters = chapters.slice(Math.max(0, chapters.length - 4));
console.log(`Format Context: Recent chapters count: ${recentChapters.length}`);

// Format recent chapters as context string
let recentChaptersText = "";
if (recentChapters.length > 0) {
  recentChaptersText = "### Recent Chapters for Context:\n\n";
  recentChapters.forEach(chapter => {
    recentChaptersText += `Chapter ${chapter.number}:\n${chapter.content}\n\n`;
  });
  console.log(`Generated recent chapters text: ${recentChaptersText.length} chars`);
}

// Get chapter summaries
let summariesText = "";
try {
  if ($('Get Chapter Summaries') && $('Get Chapter Summaries').item && $('Get Chapter Summaries').item.json) {
    summariesText = $('Get Chapter Summaries').item.json.content || "";
    console.log(`Successfully accessed summaries text: ${summariesText.length} chars`);
  }
} catch (error) {
  console.log("Error accessing summaries:", error.message);
  summariesText = "No previous chapter summaries available.";
}

// Format summaries
let formattedSummaries = "";
if (summariesText && summariesText.trim().length > 0) {
  formattedSummaries = "### Previous Chapter Summaries:\n\n" + summariesText.trim();
}

// Combine context information
const dynamicContext = formattedSummaries + 
  (recentChaptersText ? "\n\n" + recentChaptersText : "");

console.log(`Dynamic context total length: ${dynamicContext.length} chars`);
console.log(`Format Context complete`);

// Return everything
return {
  json: {
    nextChapterNumber,
    isFirstChapter: chapters.length === 0,
    recentChaptersText,
    previousChapterSummaries: formattedSummaries,
    dynamicContext,
    lastChapterContent: recentChapters.length > 0 ? recentChapters[recentChapters.length - 1].content : "",
    recentChaptersCount: recentChapters.length,
    debug: {
      dynamicContextLength: dynamicContext.length,
      recentChaptersTextLength: recentChaptersText.length,
      formattedSummariesLength: formattedSummaries.length
    }
  }
};
